// Pre-render a mouse cursor sprite via aris-render (Blitz + Vello CPU).
// The cursor is a classic white arrow with black border, rendered as HTML/CSS.
// Output: a 32x32 BGRA sprite with alpha channel for compositing.
//
// This IS aris-render output — the cursor pixels are generated by Vello CPU
// rasterizing CSS, exactly the same pipeline as the desktop. The only
// difference is we pre-render the cursor once (it never changes shape)
// and composite it at runtime.
//
// Usage: cargo run --release -p aris-render --features render --bin prerender_cursor --
//        tests/fixtures/cursor_32x32.bgra

fn main() {
    let out_path = std::env::args()
        .nth(1)
        .unwrap_or_else(|| "tests/fixtures/cursor_32x32.bgra".to_string());

    // Classic arrow cursor rendered via CSS. Uses a combination of
    // absolutely-positioned divs to form the arrow shape.
    // Black border + white fill, same as Windows/X11 cursors.
    // Each div is a small rectangle — Blitz renders these reliably.
    let html = r##"<!DOCTYPE html><html><head><style>
* { margin:0; padding:0; box-sizing:border-box; }
html, body { width:32px; height:32px; overflow:hidden; background:transparent; }
.b { background:#000000; position:absolute; }
.w { background:#ffffff; position:absolute; }
</style></head><body>
<!-- Black border (left edge of arrow) -->
<div class="b" style="left:0;top:0;width:2px;height:2px"></div>
<div class="b" style="left:0;top:2px;width:2px;height:2px"></div>
<div class="b" style="left:0;top:4px;width:2px;height:2px"></div>
<div class="b" style="left:0;top:6px;width:2px;height:2px"></div>
<div class="b" style="left:0;top:8px;width:2px;height:2px"></div>
<div class="b" style="left:0;top:10px;width:2px;height:2px"></div>
<div class="b" style="left:0;top:12px;width:2px;height:2px"></div>
<div class="b" style="left:0;top:14px;width:2px;height:2px"></div>
<div class="b" style="left:0;top:16px;width:2px;height:2px"></div>
<div class="b" style="left:0;top:18px;width:2px;height:2px"></div>
<!-- Black border (right diagonal edge) -->
<div class="b" style="left:2;top:0;width:2px;height:2px"></div>
<div class="b" style="left:4;top:2;width:2px;height:2px"></div>
<div class="b" style="left:6;top:4;width:2px;height:2px"></div>
<div class="b" style="left:8;top:6;width:2px;height:2px"></div>
<div class="b" style="left:10;top:8;width:2px;height:2px"></div>
<div class="b" style="left:12;top:10;width:2px;height:2px"></div>
<div class="b" style="left:14;top:12;width:2px;height:2px"></div>
<div class="b" style="left:16;top:14;width:2px;height:2px"></div>
<div class="b" style="left:18;top:16;width:2px;height:2px"></div>
<!-- White fill (the arrow body) -->
<div class="w" style="left:2;top:2;width:2px;height:2px"></div>
<div class="w" style="left:2;top:4;width:2px;height:2px"></div>
<div class="w" style="left:2;top:6;width:2px;height:2px"></div>
<div class="w" style="left:2;top:8;width:2px;height:2px"></div>
<div class="w" style="left:2;top:10;width:2px;height:2px"></div>
<div class="w" style="left:2;top:12;width:2px;height:2px"></div>
<div class="w" style="left:2;top:14;width:2px;height:2px"></div>
<div class="w" style="left:2;top:16;width:2px;height:2px"></div>
<div class="w" style="left:4;top:4;width:2px;height:2px"></div>
<div class="w" style="left:4;top:6;width:2px;height:2px"></div>
<div class="w" style="left:4;top:8;width:2px;height:2px"></div>
<div class="w" style="left:4;top:10;width:2px;height:2px"></div>
<div class="w" style="left:4;top:12;width:2px;height:2px"></div>
<div class="w" style="left:6;top:6;width:2px;height:2px"></div>
<div class="w" style="left:6;top:8;width:2px;height:2px"></div>
<div class="w" style="left:6;top:10;width:2px;height:2px"></div>
<div class="w" style="left:8;top:8;width:2px;height:2px"></div>
<div class="w" style="left:8;top:10;width:2px;height:2px"></div>
<div class="w" style="left:10;top:10;width:2px;height:2px"></div>
<!-- Black tail going down from the arrow base -->
<div class="b" style="left:2;top:18;width:2px;height:2px"></div>
<div class="b" style="left:4;top:16;width:2px;height:2px"></div>
</body></html>"##;

    let config = aris_render::RenderConfig {
        width: 32,
        height: 32,
        scale: 1.0,
    };

    eprintln!("[cursor] Rendering 32x32 cursor via Blitz + Vello CPU...");
    let frame = match aris_render::render_html_with_font(html, &config) {
        Ok(f) => f,
        Err(e) => {
            eprintln!("[cursor] Error: {:?}", e);
            std::process::exit(1);
        }
    };

    let non_black = frame
        .rgba
        .chunks_exact(4)
        .filter(|px| px[0] > 5 || px[1] > 5 || px[2] > 5)
        .count();
    eprintln!(
        "[cursor] Rendered: {} non-black pixels out of {}",
        non_black,
        32 * 32
    );

    // Output as BGRA (B,G,R,A) which matches the kei framebuffer format.
    // Alpha is derived from whether the pixel is non-transparent.
    let mut bgra = vec![0u8; 32 * 32 * 4];
    for i in 0..(32 * 32) {
        let src = i * 4; // RGBA
        let dst = i * 4; // BGRA
        let r = frame.rgba[src];
        let g = frame.rgba[src + 1];
        let b = frame.rgba[src + 2];
        let a = frame.rgba[src + 3];
        // If alpha is 0 or pixel is fully transparent, output transparent.
        // Otherwise output opaque pixel.
        if a > 10 && (r > 5 || g > 5 || b > 5) {
            bgra[dst] = b;
            bgra[dst + 1] = g;
            bgra[dst + 2] = r;
            bgra[dst + 3] = 0xFF; // opaque
        } else {
            bgra[dst] = 0;
            bgra[dst + 1] = 0;
            bgra[dst + 2] = 0;
            bgra[dst + 3] = 0; // transparent
        }
    }

    match std::fs::write(&out_path, &bgra) {
        Ok(()) => eprintln!("[cursor] Wrote {} bytes to {}", bgra.len(), out_path),
        Err(e) => {
            eprintln!("[cursor] Write error: {}", e);
            std::process::exit(1);
        }
    }
}
